# Example XML generated by CTest
#
# <Failure type="Error">
#     <Action>
#         <TargetName> cmake_target_name </TargetName>
#         <Language>C++</Language>
#         <SourceFile> some_path </SourceFile>
#         <OutputFile> some_path </OutputFile>
#         <OutputType>object file</OutputType>
#     </Action>
#     <Command>
#         <WorkingDirectory>/home/runner/trilinos/build-gcc-14</WorkingDirectory>
#         <Argument> /usr/bin/gcc </Argument>
#         <Argument> some_compiler_args </Argument>
#     </Command>
#     <Result>
#         <StdOut/>
#         <StdErr>
#           error_message
#         </StdErr>
#         <ExitCondition>0</ExitCondition>
#     </Result>
#     <Labels>
#         <Label> ... </Label>
#     </Labels>
# </Failure>


@dataclass
class BuildTargetInfo:
    """CMake target info from CTest generated XMLs"""
    info_type: str
    target_name: str
    source_file: str
    output_file: str
    output_type: str
    command: str
    stderr: str
    exit_val: str

    def __str__(self):
        msg = f"""
            {self.info_type} when building {self.output_type} {self.output_file}:
            Command: {self.command}
            {self.stderr}
        """
        return msg

    def pretty_print(self):
        print(f"Info type: {self.info_type}")
        print(f"Target: {self.target_name}")
        print(f"Source file: {self.source_file}")
        print(f"Output file: {self.output_file}")
        print(f"Output file type: {self.output_type}")
        print(f"Command: {self.command}")
        print(f"stderr output: {self.stderr}")
        print(f"Exit value: {self.exit_val}")


def parse_into_target_info(xml_file: str) -> BuildTargetInfo:
    tree = ET.parse(xml_file)
    root = tree.getroot()

    # Parse Action tags
    info_type = (root.get("type") or "").strip()
    target_name = (root.findtext(".//Action/TargetName") or "").strip()
    source_file = (root.findtext(".//Action/SourceFile") or "").strip()
    output_file = (root.findtext(".//Action/OutputFile") or "").strip()
    output_type = (root.findtext(".//Action/OutputType") or "").strip()

    # Parse Command tags
    workdir = (root.findtext(".//Command/WorkingDirectory") or "").strip()
    args = [(a.text or "").strip() for a in root.findall(".//Command/Argument")]
    args = [a for a in args if a]
    command = " ".join(([workdir] if workdir else []) + args)

    # Parse Result tags
    stderr = (root.findtext(".//Result/StdErr") or "").strip()
    exit_val = (root.findtext(".//Result/ExitCondition") or "").strip()

    return BuildTargetInfo(
        info_type=info_type,
        target_name=target_name,
        source_file=source_file,
        output_file=output_file,
        output_type=output_type,
        command=command,
        stderr=stderr,
        exit_val=exit_val,
    )


def handle_build_errors(args):
    xml_path = args.ctest_xml_dir
    xml_files = [f.name for f in xml_path.glob("*.xml") if f.is_file() and "error" in f.name]
    [print(e) for e in xml_files]
    for f in xml_files:
        target_info = parse_into_target_info(xml_path / f)
        print(target_info)


def handle_build_warnings(args):
    xml_path = args.ctest_xml_dir
    xml_files = [f.name for f in xml_path.glob("*.xml") if f.is_file() and "warning" in f.name]
    [print(e) for e in xml_files]
    for f in xml_files:
        target_info = parse_into_target_info(xml_path / f)
        print(target_info)

def parse_args(argv=None):
    parser = argparse.ArgumentParser()
    parser.add_argument(
        "--ctest-xml-dir",
        required=True,
        type=Path,
        help="Path to CTest testing directory.",
    )
    parser.add_argument(
        "--build-errors",
        action="store_true",
        help="Parse CTest-generated warning XML files.",
    )
    parser.add_argument(
        "--build-warnings",
        action="store_true",
        help="Parse CTest-generated warning XML files.",
    )
    return parser.parse_args()


def main(argv=None) -> int:
    args = parse_args(argv)

    if args.build_errors:
        handle_build_errors(args)
    if args.build_warnings:
        handle_build_warnings(args)

    return 0

if __name__ == "__main__":
    main()
